<?php
require_once dirname(__DIR__) . '/includes/cms.php';if($_SERVER['REQUEST_METHOD']!=='POST'||!validarTokenCsrf($_POST['csrf_token']??null)){cmsFlash('error','Solicitud o token CSRF inválido.');header('Location: index.php');exit;}$id=cmsId($_POST['id']??0);$accion=(string)($_POST['accion']??'');if(!$id){cmsFlash('error','ID inválido.');header('Location: index.php');exit;}$pdo=obtenerConexion();
try{if($accion==='toggle'){$q=$pdo->prepare('UPDATE elementos_seccion SET activo=1-activo WHERE id=:id');$q->execute(['id'=>$id]);cmsFlash('exito','Estado actualizado.');}elseif($accion==='eliminar'){$q=$pdo->prepare('SELECT imagen FROM elementos_seccion WHERE id=:id');$q->execute(['id'=>$id]);$imagen=$q->fetchColumn();$q=$pdo->prepare('DELETE FROM elementos_seccion WHERE id=:id');$q->execute(['id'=>$id]);cmsEliminarImagenSiNoSeUsa($imagen?:null);cmsFlash('exito','Elemento eliminado.');}else cmsFlash('error','Acción no válida.');}catch(Throwable $e){error_log($e->getMessage());cmsFlash('error','No fue posible completar la acción.');}header('Location: index.php');exit;
